class Solution {
public:
    int addMinimum(string word) {
        int count = 0;
        for (char c : word) {
            if (c == 'a') {
                count += 2;
            } else if (c == 'b') {
                count++;
            } else if (c == 'c') {
                count++;
            }
        }
        return count;
    }
};
